<?php get_header(); ?><main id="main-content" class="site-main"><header class="archive-header"><span class="eyebrow">Explore por assunto</span><h1><?php the_archive_title(); ?></h1><?php the_archive_description('<p>', '</p>'); ?></header><section class="archive-grid"><div class="article-grid"><?php if (have_posts()) : while (have_posts()) : the_post(); ?><article class="article-card"><a href="<?php the_permalink(); ?>"><img src="<?php echo esc_url(lockegames_image(get_the_ID())); ?>" alt="<?php the_title_attribute(); ?>"></a><span class="meta"><?php echo esc_html(get_the_date('j \d\e F \d\e Y')); ?></span><h3><a href="<?php the_permalink(); ?>"><?php the_title(); ?></a></h3><p><?php echo esc_html(wp_trim_words(get_the_excerpt(), 18)); ?></p></article><?php endwhile; else : ?><div class="empty-state">Ainda não há publicações nesta seção.</div><?php endif; ?></div><?php the_posts_pagination(array('mid_size' => 1, 'prev_text' => '←', 'next_text' => '→', 'class' => 'pagination')); ?></section></main><?php get_footer(); ?>
